#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=3200005;
int n,m,k,ans,numm[N],ls[N],rs[N],tr1[N],tr2[N],sum[N];
void update(int u)
{
	tr1[u]=tr1[ls[u]]?tr1[ls[u]]:tr1[rs[u]];
	tr2[u]=tr2[rs[u]]?tr2[rs[u]]:tr2[ls[u]];
	sum[u]=sum[ls[u]]+sum[rs[u]]-(tr2[ls[u]]+1==tr1[rs[u]]);
}
void fun(int &num,int l,int r,int x)
{
	if(num==0)
	{
		k++;
		num=k;	
	}
	if(l==r)
	{
		tr1[num]=tr2[num]=x,sum[num]=1;
		return ;
	}
	int mid=(l+r)/2;
	if(x<=mid) fun(ls[num],l,mid,x);
	else fun(rs[num],mid+1,r,x);
	update(num);
}
void fun2(int &x,int &y,int l,int r)
{
	if(!x||!y)
	{
		x+=y;
		return ;
	}
	if(l==r)
	{
		tr1[x]=tr2[x]=l,sum[x]=1;
		return;
	}
	int mid=(l+r)/2;
	fun2(ls[x],ls[y],l,mid);
	fun2(rs[x],rs[y],mid+1,r);
	update(x);
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n>>m;
	for(int i=1;i<=n;i++)
	{
		int x;
		cin>>x;
		ans-=sum[numm[x]];
		fun(numm[x],1,n,i);
		ans+=sum[numm[x]];
	}
	for(int i=1;i<=m;i++)
	{
		int op,x,y;
		cin>>op;
		if(op==1)
		{
			cin>>x>>y;
			if(x==y) continue;
			ans-=(sum[numm[x]]+sum[numm[y]]);
			fun2(numm[y],numm[x],1,n);
			numm[x]=0;
			ans+=sum[numm[y]];
		}
		else cout<<ans<<"\n";
	}
	return 0;
}
